local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxModuleMgr:LxBaseMgr
local LxModuleMgr = classX("LxModuleMgr", LxBaseMgr)

function LxModuleMgr:Initialize()
    LxBaseMgr.Initialize(self)

    ---@type table<string, LxBaseModule>
    self._modules = {}
    ---@type table<string, boolean>
    self._regModules = {}

    for k,v in pairs(ModuleNames) do
        self:RegModule(v)
    end
end

function LxModuleMgr:Dispose()
    for k,v in pairs(self._modules) do
        v:Dispose()
    end
    LxBaseMgr.Dispose(self)
end

function LxModuleMgr:RegModule(name)
    self._regModules[name] = true
end

---@param module LxBaseModule
function LxModuleMgr:AddModule(name, module)
    self._modules[name] = module
    module:Initialize()
end

function LxModuleMgr:RemoveModule(name)
    local module = self._modules[name]
    if module then
        self._modules[name] = nil
        module:Dispose()
    end
end

---@return LxBaseModule
function LxModuleMgr:GetModule(name)
    local module = self._modules[name]
    if module ~= nil then
        return module
    end
    if not self._regModules[name] then return end
    module = require(string.format("LApp.module.Lx%sModule", name)):New()
    self:AddModule(name, module)
    return module
end

---登录完成了，可以清理一些不能有的数据
function LxModuleMgr:LoginOk()
    for k,v in pairs(self._modules) do
        v:LoginOk()
    end
end


return LxModuleMgr
